texttool_globals_dialog_message___popup_search_connectivity_privacy_mode_active_content = TextObject(bs_BA="Aktivirajte mobilne podatke da biste mogli koristiti online\nfunkcije.", cs_CZ="Aktivujte prosím mobilní data, abyste mohli využívat online\nfunkce.", da_DK="Aktiver mobildata for at kunne anvende onlinefunktioner.", de_DE="Bitte aktiviere die mobilen Daten, um die Online-Funktionen\nnutzen zu können.", el_GR="Ενεργοποιήσετε τα δεδομένα κινητής τηλεφωνίας, για να\nμπορέσετε να χρησιμοποιήσετε τις online λειτουργίες.", en_GB="Please activate mobile data to use the online functions.", es_ES="Por favor, active los datos móviles para poder utilizar las\nfunciones online.", fi_FI="Aktivoi mobiilidata käyttääksesi online-toimintoja.", fr_FR="Veuillez activer les données mobiles pour pouvoir utiliser les\nfonctions en ligne.", hr_HR="Aktivirajte mobilne podatke kako biste koristili online\nfunkcije.", hu_HU="Kérünk, az online funkciók használatához aktiváld a mobil\nadatokat.", it_IT="Attivare i dati mobili per poter utilizzare le funzioni online.", nl_NL="Activeer de mobiele data om de onlinefuncties te kunnen\ngebruiken.", no_NO="Du må aktivere mobildata for å kunne bruke\nonline-funksjonene.", pl_PL="Aby korzystać z funkcji online, proszę wyłączyć dane\nmobilne.", pt_PT="Por favor, ativa os dados móveis para poderes utilizar as\nfunções online.", ro_RO="Activaţi datele mobile, pentru a putea utiliza funcţiile online.", ru_RU="Активируйте мобильные данные, чтобы иметь\nвозможность пользоваться онлайн-функциями.", sk_SK="Prosím, aktivujte si mobilné dáta, aby ste mohli využívať\nonline funkcie.", sl_SI="Za uporabo spletnih funkcij aktivirajte mobilne podatke.", sr_RS="Aktivirajte mobilne podatke da biste mogli da koristite onlajn\nfunkcije.", sv_SE="Aktivera mobildata för att kunna använda\nonlinefunktionerna.", tr_TR="Çevrimiçi fonksiyonu kullanabilmek için, lütfen mobil verileri\netkinleştir.", uk_UA="Активуйте мобільні дані, щоб мати змогу користуватися\nонлайн функціями.")
texttool_globals_dialog_message___popup_search_connectivity_privacy_mode_active_title = TextObject(bs_BA="Mobilni podaci deaktivirani", cs_CZ="Mobilní data deaktivována", da_DK="Mobildata deaktiveret", de_DE="Mobile Daten deaktiviert", el_GR="Δεδομένα κινητής τηλεφωνίας απενεργοποιημένα", en_GB="Mobile data deactivated", es_ES="Datos móviles desactivados", fi_FI="Mobiilidata deaktivoitu", fr_FR="Données mobiles désactivées", hr_HR="Mobilni podaci deaktivirani", hu_HU="Mobil adatok kikapcsolva", it_IT="Dati mobili disattivati", nl_NL="Mobiele data gedeactiveerd", no_NO="Mobildata er deaktivert", pl_PL="Dane mobilne wyłączone", pt_PT="Dados móveis desativados", ro_RO="Date mobile dezactivate", ru_RU="Мобильные данные деактивированы", sk_SK="Mobilné dáta deaktivované", sl_SI="Mobilni podatki deaktivirani", sr_RS="Mobilni podaci deaktivirani", sv_SE="Mobildata har avaktiverats", tr_TR="Mobil veriler devre dışı bırakıldı", uk_UA="Мобільні дані деактивовано")
